function maxKilledEnemies(grid) {
    if (!grid.length) return 0;
    let m = grid.length, n = grid[0].length, result = 0, rowhits;
    let colhits = new Array(n).fill(0);
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (j === 0 || grid[i][j - 1] === 'W') {
                rowhits = 0;
                for (let k = j; k < n && grid[i][k] !== 'W'; k++)
                    rowhits += grid[i][k] === 'E' ? 1 : 0;
            }
            if (i === 0 || grid[i - 1][j] === 'W') {
                colhits[j] = 0;
                for (let k = i; k < m && grid[k][j] !== 'W'; k++)
                    colhits[j] += grid[k][j] === 'E' ? 1 : 0;
            }
            if (grid[i][j] === '0') result = Math.max(result, rowhits + colhits[j]);
        }
    }
    return result;
}
```

    Initialize `result` to keep track of the maximum number of enemies that can be killed. Then, initialize `rowhits` and `colhits` to store the number of enemies in the current row and column.

Loop through the `grid`. When you start a new row or encounter a wall in the previous cell, reset `rowhits` and count the number of enemies in the row. If you are in the first row, or encounter a wall in the cell above, reset the `colhits` for that column and count the number of enemies in the column.

If you encounter an empty cell, update the `result` with the maximum of its current value and the sum of `rowhits` and `colhits` for that position.

Return `result`.

